+    fn visual_start_position(&self, pane: PaneFocus, right_content: &str) -> TextPosition {
+        match pane {
+            PaneFocus::Left => TextPosition {
+                row: self.control_selected,
+                column: 0,
+            },
+            PaneFocus::Right => {
+                let visible_content = self.visible_right_content(right_content);
+                let lines = visible_content.lines().collect::<Vec<_>>();
+                let row = lines.len().saturating_sub(1);
+                let column = lines
+                    .last()
+                    .map(|line| line.chars().count().saturating_sub(1))
+                    .unwrap_or(0);
+                TextPosition { row, column }
+            }
