+
+    fn move_visual_cursor(&mut self, row_delta: isize, column_delta: isize) {
+        let Some(selection) = self.visual_selection.clone() else {
+            return;
+        };
+        let (width, height) = self.visual_bounds(selection.pane);
+        let Some(selection) = &mut self.visual_selection else {
+            return;
+        };
+        selection.cursor.row = offset_index(selection.cursor.row, row_delta, height);
+        selection.cursor.column = offset_index(selection.cursor.column, column_delta, width);
+    }
+
+    fn visual_bounds(&self, pane: PaneFocus) -> (usize, usize) {
+        let body_height = self.height.saturating_sub(1);
+        let inner_height = usize::from(body_height.saturating_sub(2).max(1));
+        match pane {
+            PaneFocus::Left => {
+                let width = usize::from(self.layout().left_width.saturating_sub(2).max(1));
+                let height = self.left_pane_text_lines().len().max(1).min(inner_height);
+                (width, height)
+            }
+            PaneFocus::Right => {
+                let (width, height) = self.right_inner_size();
+                (usize::from(width.max(1)), usize::from(height.max(1)))
+            }
+        }
+    }
+
+    fn visual_cursor_position(&self, selection: &VisualSelection) -> (u16, u16) {
+        let row = 2_u16.saturating_add(selection.cursor.row.min(usize::from(u16::MAX)) as u16);
+        let column = match selection.pane {
+            PaneFocus::Left if self.left_visible => {
+                2_u16.saturating_add(selection.cursor.column.min(usize::from(u16::MAX)) as u16)
+            }
+            _ => self.layout().left_width.saturating_add(2).saturating_add(
+                selection.cursor.column.min(usize::from(u16::MAX)) as u16,
+            ),
+        };
+        (row, column)
+    }
+
+    fn render_visual_selection(
+        &self,
+        buffer: &mut Buffer,
+        left_pane: Option<Rect>,
+        right_pane: Rect,
+    ) {
+        let Some(selection) = &self.visual_selection else {
+            return;
+        };
+        let pane = match selection.pane {
+            PaneFocus::Left => {
+                let Some(left_pane) = left_pane else {
+                    return;
+                };
+                left_pane
+            }
+            PaneFocus::Right => right_pane,
+        };
+        let inner = inner_rect(pane);
+        if inner.width == 0 || inner.height == 0 {
+            return;
+        }
+
+        let min_row = selection.anchor.row.min(selection.cursor.row);
+        let max_row = selection
+            .anchor
+            .row
+            .max(selection.cursor.row)
+            .min(usize::from(inner.height.saturating_sub(1)));
+        let min_column = selection.anchor.column.min(selection.cursor.column);
+        let max_column = selection
+            .anchor
+            .column
+            .max(selection.cursor.column)
+            .min(usize::from(inner.width.saturating_sub(1)));
+
+        for row in min_row..=max_row {
+            let (start_column, end_column) = match selection.kind {
+                VisualSelectionKind::Line => (0, usize::from(inner.width.saturating_sub(1))),
+                VisualSelectionKind::Block => (min_column, max_column),
+                VisualSelectionKind::Character if min_row == max_row => (min_column, max_column),
+                VisualSelectionKind::Character if row == min_row => {
+                    (selection_column_on_row(selection, row), usize::from(inner.width.saturating_sub(1)))
+                }
+                VisualSelectionKind::Character if row == max_row => {
+                    (0, selection_column_on_row(selection, row).min(usize::from(inner.width.saturating_sub(1))))
+                }
+                VisualSelectionKind::Character => (0, usize::from(inner.width.saturating_sub(1))),
+            };
+            for column in start_column..=end_column {
+                let x = inner.x.saturating_add(column as u16);
+                let y = inner.y.saturating_add(row as u16);
+                buffer.get_mut(x, y).modifier.insert(Modifier::REVERSED);
+            }
+        }
+    }
