+fn inner_rect(rect: Rect) -> Rect {
+    Rect::new(
+        rect.x.saturating_add(1),
+        rect.y.saturating_add(1),
+        rect.width.saturating_sub(2),
+        rect.height.saturating_sub(2),
+    )
+}
+
+fn offset_index(index: usize, delta: isize, len: usize) -> usize {
+    let max = len.saturating_sub(1);
+    if delta.is_negative() {
+        index.saturating_sub(delta.unsigned_abs()).min(max)
+    } else {
+        index.saturating_add(delta as usize).min(max)
+    }
+}
+
+fn selection_column_on_row(selection: &VisualSelection, row: usize) -> usize {
+    if selection.anchor.row == row {
+        selection.anchor.column
+    } else {
+        selection.cursor.column
+    }
+}
+
+fn selected_line_range(lines: &[String], min_row: usize, max_row: usize) -> Option<&[String]> {
+    if min_row >= lines.len() {
+        return None;
+    }
+    let max_row = max_row.min(lines.len().saturating_sub(1));
+    Some(&lines[min_row..=max_row])
+}
+
+fn selected_character_text(
+    rows: &[String],
+    anchor: TextPosition,
+    cursor: TextPosition,
+    min_row: usize,
+    max_row: usize,
+) -> String {
+    let (start, end) = if (anchor.row, anchor.column) <= (cursor.row, cursor.column) {
+        (anchor, cursor)
+    } else {
+        (cursor, anchor)
+    };
+    rows.iter()
+        .enumerate()
+        .map(|(offset, line)| {
+            let row = min_row + offset;
+            if min_row == max_row {
+                slice_chars(line, start.column, end.column.saturating_add(1))
+            } else if row == min_row {
+                slice_chars(line, start.column, usize::MAX)
+            } else if row == max_row {
+                slice_chars(line, 0, end.column.saturating_add(1))
+            } else {
+                line.to_string()
+            }
+        })
+        .collect::<Vec<_>>()
+        .join("\n")
+}
+
+fn slice_chars(text: &str, start: usize, end: usize) -> String {
+    text.chars()
+        .skip(start)
+        .take(end.saturating_sub(start))
+        .collect()
+}
